from skimage import io, img_as_floatfrom skimage.filters import gaussianfrom matplotlib import pyplot as pltimg = img_as_float(    io.imread("../data/einstein_blurred.jpg", as_gray=True))# Create blurred imageblurred = gaussian(img, sigma=3)# Extract high-frequency detailsdetail = img - blurred# Add details backsharpened = img + detailplt.figure(figsize=(10,5))plt.subplot(1,2,1)plt.imshow(img, cmap='gray')plt.title("Original")plt.subplot(1,2,2)plt.imshow(sharpened, cmap='gray')plt.title("Sharpened")plt.show()# radius: Gaussian blur sigma# amount: sharpening strength#unsharped_img = unsharp_mask(img, radius=3, amount=1)